   $('#item-blockFieldset-10').hide();
 });
</script>


			You will need to install the <a target="_blank" onclick="return openAppPage('uaparser');" href="https://splunkbase.splunk.com/app/3003/">HTTP User-Agent parser</a> app in order to extract formated fields from user agents.

<style>#item-blockFieldset-10{ display:none; }</style>
